          const href = userLink.getAttribute("href");
          const match = href.match(/^\/([^\/\?]+)/);
          if (match && match[1] && !match[1].includes("status") && !match[1].includes("hashtag")) {
            username = match[1];
          }
        }
      }
      if (!username) {
        const userLinks = article.querySelectorAll("a[href^=\"/\"]");
        for (const link of userLinks) {
          const href = link.getAttribute("href");
          const text = link.textContent || "";
          if (href && href.startsWith("/") && !href.includes("/status/") && !href.includes("/hashtag/") && !href.includes("/search") && !href.includes("/i/") && !href.includes("/explore") && !href.includes("/photo/") && !href.includes("/video/") && !href.includes("/analytics")) {
            const match = href.match(/^\/([^\/\?]+)/);
            if (match && match[1] && match[1].length > 0 && (text.includes("@") || /^[a-zA-Z0-9_]+$/.test(match[1]))) {
              username = match[1];
              break;
            }
          }
        }
      }
      const statusLink = article.querySelector("a[href*=\"/status/\"]");
      if (!statusLink) return null;
      const href = statusLink.getAttribute("href");
      if (!href || !href.includes("/status/")) return null;
      const url = href.startsWith("http") ? href : `https://x.com${href}`;

      if (username && url) {
        return { username, statusUrl: url, statusLink, article };
      }
      return null;
    } catch (e) {
      searchCount.error++;
      return null;
    }
  }

  async function searchPosts() {
    // ťĚě„āĘ„āĮ„ÉÜ„ā£„ÉĖś§úŚáļ
    const isInactive = document.hidden || document.visibilityState === 'hidden';
    if (isInactive) {
      console.warn('Window is inactive/hidden, some operations may be delayed');
    }
    const processedArticleIds = new Set();
    const skipReasons = []; // Collect skip reasons for debugging
    const candidates = []; // Collect all valid posts
    const targetCandidates = 10; // Stop when we find 10 candidates

    let scrollAttempts = 0;
    const maxScrollAttempts = 10; // Maximum scroll attempts

    while (scrollAttempts < maxScrollAttempts && candidates.length < targetCandidates) {
      // Get all articles currently visible
      const articles = Array.from(document.querySelectorAll("article"));

      // Process each article
      for (const article of articles) {
        // Stop if we have enough candidates
        if (candidates.length >= targetCandidates) break;

        const statusLink = article.querySelector("a[href*=\"/status/\"]");
        let articleId = null;
        if (statusLink) {
          const href = statusLink.getAttribute("href");
          if (href) {
            articleId = href.includes("/status/") ? href : null;
          }
        }
        if (!articleId) {
          articleId = article.getAttribute("data-testid") || article.id || article.textContent?.slice(0, 50) || Math.random().toString();
        }
        if (processedArticleIds.has(articleId)) continue;
        processedArticleIds.add(articleId);

        const result = await checkArticle(article);
        // Collect valid posts instead of clicking immediately
        if (result && result.username && result.statusUrl) {
          searchCount.found++;
          candidates.push({
            username: result.username,
            statusUrl: result.statusUrl,
            statusLink: result.statusLink,
            article: result.article
          });
        } else {
          searchCount.skipped++;
          if (result && result.skipped) {
            skipReasons.push({ articleId, reason: result.reason, debugInfo: result.debugInfo });
          } else {
            skipReasons.push({ articleId, reason: "unknown skip reason" });
          }
        }
      }

      // Stop if we have enough candidates
      if (candidates.length >= targetCandidates) break;

      // Scroll down to load more posts
      scrollAttempts++;
      if (scrollAttempts < maxScrollAttempts) {
        window.scrollBy(0, 500);
        await new Promise(r => setTimeout(r, 1000)); // Wait for new content to load
      }
    }

    // If no candidates found, return early
    if (candidates.length === 0) {
      return { skipReasons: skipReasons };
    }

    // Randomly select one candidate
    const selected = candidates[Math.floor(Math.random() * candidates.length)];

    // Scroll to the selected post and click
    // ťĚě„āĘ„āĮ„ÉÜ„ā£„ÉĖśôā„Āß„āāŚčēšĹú„Āô„āč„āą„ĀÜ„ĀęÁõīśé•„āĻ„āĮ„É≠„Éľ„ÉęšĹćÁĹģ„āíŤ®≠Śģö
      const articleRect = selected.article.getBoundingClientRect();
      const scrollY = window.scrollY + articleRect.top - window.innerHeight / 2;
      window.scrollTo({ top: scrollY, behavior: 'smooth' });
    await new Promise(r => setTimeout(r, 1000));

    window.__targetUsername = selected.username;
    window.__targetStatusUrl = selected.statusUrl;
    const targetArticle = selected.article;
    selected.statusLink.click();

    let waitCount = 0;
    const maxWaitCount = 40;
    while (waitCount < maxWaitCount) {
      if (!targetArticle.isConnected) {
        return { didAction: true, reason: `found and navigated to target post (selected from ${candidates.length} candidates)`, stats: searchCount, username: selected.username, statusUrl: selected.statusUrl, skipReasons: skipReasons };
      }
      await new Promise(r => setTimeout(r, 500));
      waitCount++;
    }

    return { didAction: false, reason: "article element did not disappear after click", skipReasons: skipReasons };
  }

  let result = await searchPosts();
  if (result && result.username && result.statusUrl) return result;

  return { didAction: false, reason: `no suitable post found`, stats: searchCount, skipReasons: result?.skipReasons || [] };
})()

